(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).ru = [
  { id:1, topic:"Наука о мытье рук", emoji:"🧼",
    question:"Когда на руках есть микробы или вирусы, вызывающие болезни, почему мыть их с « мылом » намного безопаснее, чем мыть одной водой?",
    choices:["Форма мыльных пузырей пугает микробов и прогоняет их далеко","Мыло способно полностью разрушить жировую плёнку (наружную оболочку), которая окутывает вирус, и растворить её","Мыло делает кожу рук твёрдой, как железо, и отталкивает микробов","Запах мыла мешает микробам дышать"],
    answerIndex:1,
    explanation:"Поверхность многих микробов и вирусов (например, гриппа) на самом деле защищена тонкой жировой плёнкой, которая называется « липид ». Именно эта плёнка даёт им силу вторгаться в тело человека. Жир никогда не смыть одной водой, но молекулы мыла умеют окружать жир и растворять его в воде. Когда ты с силой трёшь руки мылом, жировая плёнка, защищающая вирус, мгновенно растворяется в клочья, вирус уже не может оставаться живым и полностью уничтожается. Мытьё с мылом не просто смывает микробов с рук — это сильнейшее « лекарство », которое научно истребляет врага." },
  { id:2, topic:"Прямое давление", emoji:"🩹",
    question:"Когда от глубокой раны кровь хлещет потоком, какое « правильное первое действие (прямое давление) » нужно сделать в самую первую очередь, чтобы спасти жизнь?",
    choices:["Всё время мягко поглаживать рану тканью, смоченной водой","Приложить чистую ткань прямо к ране и сильно давить сверху, навалившись всем телом","Резко размахивать раной, пока кровь не остановится","Облепить рану грязью, чтобы остановить кровь"],
    answerIndex:1,
    explanation:"Потерять много крови — самая большая опасность: кислород перестаёт поступать к клеткам, и жизнь можно потерять в считаные мгновения. Всемирная основа медицины, которая это предотвращает, — « прямое давление ». Сильно прижимая разорванный сосуд снаружи, ты физически закрываешь путь, по которому течёт кровь. Кроме того, нажимая, ты помогаешь « тромбоцитам » крови — команде, которая строит корочку, — собраться у раны и заделать прорванную дырку. Если вытирать слабо и кое-как, кровь не остановить. Мудрость сильного давления двумя руками удерживает чью-то жизнь." },
  { id:3, topic:"Шина при переломе", emoji:"🦴",
    question:"Когда после падения подозревают « перелом кости ноги или руки », почему это место ни в коем случае нельзя силой заставлять двигаться?",
    choices:["От движения кость вдруг превратится в круглый шар","Острый конец сломанной кости может изрезать важные мышцы, сосуды и нервы под кожей и вызвать сильное кровотечение или паралич","От движения кость станет в десять раз тяжелее","Кость испугается и исчезнет из тела"],
    answerIndex:1,
    explanation:"Когда кость с хрустом ломается под кожей, сломанный конец очень острый и колкий, как осколок стекла. Если ты силой заставишь это место двигаться, гадая « смогу ли я идти? », этот острый костяной нож начнёт двигаться внутри одежды и мышц, разрежет толстый соседний сосуд и вызовет внутреннее кровотечение или повредит нерв и вызовет паралич, который никогда не заживёт. При подозрении на перелом приложи ветку или твёрдую доску (шину) и одновременно закрепи сустав выше и сустав ниже места перелома, чтобы оно не сдвинулось ни на миллиметр, пока ждёшь помощи. Это и есть верная мудрость первой помощи." },
  { id:4, topic:"Помощь при ожоге", emoji:"🔥",
    question:"Когда коснулся огня или кипятка и получил ожог, что нужно сделать самым первым, очень спеша, прежде всего?",
    choices:["Намазать рану маслом или грязью, чтобы она не сохла","Охлаждать рану чистой холодной водой не меньше 15 минут, пока боль не утихнет","Аккуратно содрать обожжённую кожу ногтями","Завернуть в тёплую ткань, чтобы сохранить тепло"],
    answerIndex:1,
    explanation:"Страшное в ожоге то, что даже после того, как ты убрал руку от горячего предмета, огромная тепловая энергия, оставшаяся на поверхности кожи, продолжает, как тлеющий уголь, просачиваться глубже в кожу (в дерму и мышечный слой) и разрушать клетки. Остановить это можно только одним способом — как можно быстрее отнять это тепло холодной водой. Охлаждение дольше 15 минут останавливает волну тепла, идущую вглубь, и делает рану как можно более поверхностной. Если раннего охлаждения мало, кожа глубоко отмирает, остаётся большой шрам на всю жизнь, и микробам легче проникнуть. Охлаждать водой — это научный « тормоз » против распространения ожога." },
  { id:5, topic:"Раствор для питья", emoji:"🥤",
    question:"Когда сильный понос или рвота высушили тело, почему с научной точки зрения лучше пить воду, смешанную с небольшим количеством « соли » и « сахара » (раствор для питья), чем простую воду?",
    choices:["Если смешать соль и сахар, вода станет вкусной и поднимет настроение","В стенке тонкого кишечника есть особая дверь, которая впитывает воду с огромной скоростью, когда соль (натрий) и сахар (глюкоза) приходят вместе","Соль напрямую сжигает и убивает микробов поноса","Если выпить сахар, живот мгновенно замёрзнет и понос остановится"],
    answerIndex:1,
    explanation:"При сильном поносе или рвоте стенка кишечника повреждена, поэтому даже простая вода плохо впитывается и выходит с другого конца. Но в стенке тонкого кишечника человека есть дверь (SGLT-1): когда натрий и глюкоза приходят вместе в соотношении 1 к 2, она мгновенно, как мощный насос, всасывает воду в клетки. На этом основан « раствор для питья », спасший много жизней по всему миру. Эта волшебная вода, сделанная из половины чайной ложки соли и четырёх с половиной столовых ложек сахара на один литр воды, может надёжно спасти жизнь от обезвоживания даже там, где нет капельницы. Это мудрость медицины." },
  { id:6, topic:"Память иммунитета", emoji:"💉",
    question:"Стоит человеку переболеть некоторой сильной болезнью, например корью, как он почти не заболевает ею снова. Как называется эта замечательная система внутри тела?",
    choices:["Омоложение костей","Система памяти иммунитета","Кристаллизация крови","Иллюзия мозга"],
    answerIndex:1,
    explanation:"Внутри нашего тела команда иммунитета, включая « лейкоциты », что бьются с микробами и вирусами, патрулирует круглые сутки. Когда злой вирус вторгается впервые, на создание оружия (антитела) против него уходит много дней, и за это время можно тяжело заболеть. Но удивительно в команде иммунитета то, что она полностью запоминает « облик и приметы » врага, с которым однажды билась, и хранит их в мозге и клетках. Спустя годы, когда тот же враг вторгается снова, она по этой памяти мгновенно создаёт огромное количество точного оружия и одним ударом уничтожает его, прежде чем ты заболеешь. Технология, использующая это, — безопасно посадить лишь память до болезни — это « вакцина (прививка) »." },
  { id:7, topic:"Если укусил зверь", emoji:"🐕",
    question:"Когда тебя укусил дикий пёс, лиса, летучая мышь или другой зверь, даже если рана кажется маленькой, почему нужно срочно промыть её обильной водой с мылом — это вопрос жизни и смерти?",
    choices:["Цвет с зубов зверя может перейти на твою кожу","В слюне зверя может прятаться страшный вирус, как бешенство, который разрушает мозг и убивает почти 100% заражённых","Если не промыть, на месте укуса вырастет новая шерсть","Чтобы выразить зверю свою благодарность"],
    answerIndex:1,
    explanation:"По всему миру есть страшная болезнь под названием « бешенство », которая передаётся людям, когда их кусает зверь — носитель вируса. Если этот вирус попадает в тело и по нервам доходит до мозга, то, как только появляются признаки, даже современная медицина почти никогда не спасает человека, и он умирает. Однако есть короткий запас времени, прежде чем вирус из раны войдёт в нервы. Сразу после укуса, яростно промывая рану обильной чистой проточной водой с мылом дольше 15 минут, ты физически смываешь и уменьшаешь прилипший к ране вирус и можешь не дать ему дойти до мозга. Если укусил зверь — « прежде всего сильно промой »: это абсолютное правило медицины, что решает жизнь или смерть." },
  { id:8, topic:"Ядовитые существа", emoji:"🐍",
    question:"Когда ядовитая змея, паук или другое опасное существо укусило руку или ногу, какое « неправильное действие » нельзя совершать ни в коем случае?",
    choices:["Не двигать местом укуса и тихо лечь","Запаниковать, громко кричать и в спешке бегать кругом, спасаясь","Сказать взрослому рядом, какое именно существо тебя укусило","Держать рану ниже сердца"],
    answerIndex:1,
    explanation:"Когда тебя укусило ядовитое существо, если ты в страхе паникуешь, бегаешь кругом или шумишь, биение сердца (пульс) резко учащается. Тогда яд, попавший в рану, едет на быстро текущей крови и мгновенно расходится по мышцам, мозгу и органам всего тела, так что яд распространяется куда быстрее, и ты можешь потерять жизнь. Если укусило что-то ядовитое, правильно — успокоить сердце, не бежать, не двигаться и тихо, неподвижно лежать. Держа рану чуть ниже сердца, ты замедляешь скорость, с какой кровь с ядом возвращается к сердцу. Сохранять спокойствие и неподвижность — это и есть щит, тормозящий распространение яда." },
  { id:9, topic:"Пот и соль", emoji:"💦",
    question:"В жаркий день после обильного пота, почему пить залпом только большое количество « чистой воды без соли » на самом деле ухудшает самочувствие?",
    choices:["От чистой воды вода в желудке протухнет","Так как с потом из тела теряется и соль (натрий), питьё одной воды слишком сильно разбавляет уровень соли в крови, и мозг и мышцы не работают как надо (низкий натрий)","От слишком большого количества воды растворятся все кости тела","Чистая вода меняет твою кровь с красной на синюю"],
    answerIndex:1,
    explanation:"Жидкости тела (например, кровь) всегда содержат около 0,9% « соли », и благодаря этому точному уровню приказы нервов верно доходят до мышц и мозга. Когда сильно потеешь, эта важная соль вытекает вместе с водой. Если потом влить в это опустевшее тело только чистую воду без соли, уровень соли внутри станет ещё ниже. Тогда мозг решает « если ещё разбавится — опасно! » и отказывается от воды или пытается выбросить её с потом и мочой. В итоге ноги сильно сводит судорогой (тепловые судороги), появляются головная боль и головокружение. Восполняя жидкость в жаркий день, нужно всегда брать вместе совсем немного соли." },
  { id:10, topic:"Открыть дыхательный путь", emoji:"😮",
    question:"Когда человек упал без сознания и, возможно, не дышит, в чём настоящая цель положения « поднять подбородок вверх и запрокинуть голову назад (открыть дыхательный путь) »?",
    choices:["Повернуть лицо вверх, чтобы солнечный свет попадал в глаза","При потере сознания большая мышца в глубине горла (корень языка) обвисает вниз и полностью перекрывает путь воздуха; это предотвращает удушье","Выпрямить кости шеи, чтобы человек стал выше","Помочь упавшему человеку крепче уснуть"],
    answerIndex:1,
    explanation:"Когда человек теряет сознание и совсем обмякает, мышца « языка » в глубине горла тоже вяло западает назад. Это называют « западением языка ». Горло лежащего на спине человека полностью закрывается — путь воздуха (дыхательный путь) перекрыт собственным языком, поэтому он не может дышать и задыхается. Чтобы это предотвратить, прижимая лоб, другой рукой крепко подними кость подбородка к небу. Это физически широко раскрывает пространство в глубине горла, и воздух свободно доходит до лёгких. Это « открытие дыхательного пути » — всемирный первый шаг спасения жизни, до искусственного дыхания или сжатий грудной клетки." },
  { id:11, topic:"Как работает дыхание", emoji:"💨",
    question:"Когда мы вдыхаем и выдыхаем, почему тело должно выбрасывать газ под названием « углекислый газ »?",
    choices:["Если углекислый газ накопится в теле, кожа станет зелёной","Углекислый газ — ядовитый отход, который образуется, когда клетки сжигают питательные вещества, чтобы бодро работать, и если он копится в крови, кровь становится кислой и угрожает жизни","Если не выдыхать углекислый газ, тело раздуется, как шар, и взлетит в небо","Чтобы держать тело внутри холодным"],
    answerIndex:1,
    explanation:"Как машина сжигает бензин и выпускает выхлоп, так и триллионы клеток человека сжигают питательные вещества пищи с помощью кислорода, чтобы создать энергию жизни, и всегда создают выхлопной отход — « углекислый газ ». Когда много этого газа растворяется в крови, у него есть ядовитая сила быстро менять кровь из нейтральной в опасную « кислую ». Когда кровь становится кислой, клетки мозга и сердца уже не могут работать, и человек умирает. Именно поэтому сердце спешно гонит кровь к лёгким, на секунду раньше выбрасывает углекислый газ при дыхании и вместо него берёт свежий кислород — снова и снова." },
  { id:12, topic:"Что делает сердце", emoji:"❤️",
    question:"В чём настоящая цель того, что « сердце » в левой части груди бьётся без отдыха, ни на секунду, с рождения до смерти?",
    choices:["Растирать и измельчать пищу в желудке","Гонять по кругу « грузовик тела », который везёт кровь, полную кислорода и питательных веществ, к клеткам всего тела и собирает отходы (как углекислый газ), что выделяют клетки","Выталкивать наружу лишнюю воду, скопившуюся в теле","Разносить эхом свой звук, чтобы сообщать друзьям, где ты"],
    answerIndex:1,
    explanation:"Сердце — очень мощный мышечный насос, который двигает « кровь », текущую по нашему телу. Кровь несёт кислород, полученный в лёгких, и питательные вещества, впитанные в кишечнике, и доставляет их клеткам от макушки до кончиков пальцев ног — она играет роль важного курьера. Если сердце замрёт, ток крови полностью остановится. Тогда клетки мозга, которым нужно особенно много кислорода, всего за несколько минут испытывают его нехватку, получают необратимые разрушительные повреждения и умирают. То, что сердце продолжает биться, — важнейшая система жизнеобеспечения, доставляющая « паёк для жизни » клеткам всего тела." },
  { id:13, topic:"Спасти тонущего", emoji:"🆘",
    question:"Ты заметил друга или человека, который тонет в реке или море. Чтобы защитить себя, помогая ему, что « ни в коем случае нельзя делать »?",
    choices:["Громко крикнуть взрослым вокруг: « Кто-нибудь, сюда! Человек тонет! » и позвать на помощь","Решив, что сможешь доплыть и спасти, прыгнуть прямо в воду с пустыми руками, чтобы схватить тонущего","Бросить на воду верёвку, длинную палку или пустую пластиковую бутылку (вместо поплавка)","Протянуть руку с твёрдой земли рядом"],
    answerIndex:1,
    explanation:"Тонущий человек, который не может дышать, полностью в панике от страха смерти. Если человек подплывёт, чтобы помочь, тонущий с невероятной, свирепой силой цепляется за тебя сверху, чтобы использовать как поплавок, и заталкивает тебя под воду. Когда так случается, даже взрослый, хороший пловец, тонет вместе с ним на дно, и трагедия, когда тонут оба, повторяется по всему миру без конца. Если человек тонет, тебе самому абсолютно запрещено лезть в воду. Кричи громко с безопасного места на суше и брось всё, что « плавает », — пустую бутылку, кусок дерева, — чтобы он ухватился. Это и есть верный кодекс выживания." },
  { id:14, topic:"Профилактика столбняка", emoji:"🔩",
    question:"Когда наступил на старый ржавый гвоздь или получил глубокую рану от старого инструмента в земле, почему нельзя терять бдительность даже спустя дни, когда рана уже закрылась?",
    choices:["Ржавое железо превратится в магнит у тебя под кожей","Микроб под названием столбнячная палочка любит места без кислорода (воздуха), может размножаться в глубине раны и выделять страшный яд, что сводит судорогой все мышцы тела","Если оставить глубокую рану, через годы нога станет короче","Из старой раны вырастают новые ногти"],
    answerIndex:1,
    explanation:"В земле и старом ржавом железе прячутся споры (как яйца) микроба, вызывающего « столбняк ». Главная особенность этого микроба в том, что он « анаэробный »: ненавидит касаться воздуха. Поэтому, в отличие от мелкой поверхностной раны, его любимое место — глубина раны, куда не доходит воздух, как от глубокого укола гвоздём. После того как рана закрылась, микроб взрывообразно размножается в темноте под кожей и выделяет мощный яд, разрушающий нервы человека. Через дни–недели приходит страшная болезнь, при которой рот уже не открывается или все мышцы выгибаются назад и дышать становится невозможно. При глубокой ране нужно иметь мудрость обратиться в больницу насчёт лечения столбняка." },
  { id:15, topic:"Сильный свет и глаза", emoji:"👁️",
    question:"После того как прямо смотрел на « сильный свет » — солнце или яркие искры сварки, — почему центр зрения продолжает мерцать так, что не видно, даже если закрыть глаза?",
    choices:["Сильный свет испарил все слёзы в глазах","Клетки важнейшего экрана в глубине глаза, который ловит свет (сетчатки), получили большое повреждение, похожее на ожог, от избытка энергии, и нервы в панике","Частицы света заперлись в глазу и буянят там","Мозг вспоминает цвет света"],
    answerIndex:1,
    explanation:"В глубине глаза человека есть очень нежный нервный экран — « сетчатка », которая превращает входящий свет в электрические сигналы и шлёт их в мозг. В солнечном и очень сильном свете содержится энергия с огромной разрушительной силой, например « ультрафиолет ». Если смотреть на это прямо невооружённым глазом, на твоей сетчатке происходит то же, что когда лупа собирает солнечный свет и прожигает бумагу. Мерцание — доказательство того, что клетки кричат, потому что повреждены. Если это сильно, в центре сетчатки появляется дырка (солнечная ретинопатия), что ведёт к слепоте, когда зрение не возвращается. Отвести глаза от сильного света за одну секунду — научное правило их защиты." },
  { id:16, topic:"Зубы взрослого", emoji:"🦷",
    question:"Почему нельзя допускать, чтобы взрослые зубы (« постоянные зубы »), что вырастают примерно в старших классах начальной школы, испортились кариесом — причина на всю жизнь?",
    choices:["Если у взрослого зуба кариес, все кости головы расшатаются","В отличие от молочных, когда постоянный зуб портится кариесом и выпадает, новый снизу уже никогда не вырастет — это часть тела на всю жизнь","Потеря взрослого зуба означает, что ты совсем не сможешь говорить","Зуб с кариесом начинает двигаться сам по себе среди ночи"],
    answerIndex:1,
    explanation:"Детские зубы (молочные) сменяются, даже если в них кариес, ведь новые взрослые зубы подталкивают снизу. Но « постоянные зубы », что вырастают около 10 лет, буквально, — окончательная версия, сделанная служить до самого конца жизни. В отличие от хвоста ящерицы или человеческой кожи, твёрдая эмаль на поверхности зуба, однажды разрушенная и растворённая, на 100% никогда не восстановится в прежний вид своими силами. Потеряв зубы, ты уже не можешь измельчать пищу, что сильно вредит желудку и кишечнику, ухудшает питание всего тела и сокращает жизнь. Бережно хранить взрослые зубы — значит самому обеспечивать своё будущее здоровье." },
  { id:17, topic:"Защита мозга", emoji:"🚭",
    question:"По всему миру закон строго запрещает детям и подросткам вводить в тело « алкоголь », « табак » или опасные наркотики, что расстраивают мозг. В чём научная причина?",
    choices:["Эти вещи — привилегия взрослых, чтобы наслаждаться в одиночку","Тело ребёнка до примерно 20 лет всё ещё на полной скорости строит мозговые цепи (сеть), и если входит яд, развитие полностью останавливается, а память и контроль над чувствами ломаются навсегда","Если дети это употребляют, цвет всей одежды становится чёрным","Настоящей причины нет; это просто правило, которое взрослые придумали, чтобы ограничивать детей"],
    answerIndex:1,
    explanation:"Человеческий мозг с рождения до примерно 20 лет долго, изо дня в день, ведёт работы по прокладке сложных сетей нервных клеток, чтобы стать умнее и лучше владеть чувствами. Если в этот очень нежный период « в разгар стройки » в мозг втекают яды — алкоголь, никотин табака или наркотики вроде конопли, — проводка разрушается в хаос, и рост полностью останавливается. В итоге даже взрослым ты уже не можешь думать глубоко, срываешься и устраиваешь насилие или становишься жалким телом, что не может жить без наркотика (зависимость). Чтобы защитить мозг, держи твёрдую решимость всю жизнь не приближаться к этим ядам." },
  { id:18, topic:"Сон чистит мозг", emoji:"😴",
    question:"Когда живёшь каждый день, не высыпаясь как следует, почему люди становятся более склонны болеть и не могут ясно думать?",
    choices:["Если не спать, кости тела становятся всё легче и ломаются","Система очистки, что вымывает вредные отходы из мозга, и гормон роста, что залечивает раны тела, — работающие только во сне, — перестают работать (глимфатическая система)","Если пропустишь сон, солнце разозлится и даст жар","Если человек не спит, за 3 дня он полностью превращается в робота"],
    answerIndex:1,
    explanation:"Днём, пока мы живём, работая головой, клетки мозга выделяют много вредных белковых отходов, например « бета-амилоид », которые копятся в голове. Когда человек ночью входит в глубокий сон, клетки мозга чуть сжимаются, создавая зазоры, и в эти зазоры, как цунами, втекает чистая вода — « спинномозговая жидкость », — и начинается большая уборка, разом вымывающая дневные отходы. Это система очистки мозга, открытая недавней медициной. Если часто недосыпать, ядовитые отходы остаются грудой в голове, нервы гибнут, ты становишься раздражительным, иммунитет падает, и ты проигрываешь всякой болезни. Сон — лучшее моющее средство для мозга." },
  { id:19, topic:"Как работает наследственность", emoji:"🧬",
    question:"Во всех странах мира и на протяжении истории есть правило против брака и рождения детей с очень близкими кровными родственниками (отец и дочь, брат и сестра). В чём общая научная (генетическая) причина?",
    choices:["С близкими родственниками невозможно решить, как назвать будущего ребёнка","Каждый где-то в генах несёт небольшую ошибку чертежа (причину болезни), и у близких родственников одинаковые ошибки накладываются, поэтому вероятность ребёнка с тяжёлой болезнью или инвалидностью резко взлетает","С близкими родственниками внутри дома становится тесно","Богу не нравится такая внешность"],
    answerIndex:1,
    explanation:"Гены — чертёж тела человека — образуются, когда получают набор из двух томов: половину от отца и половину от матери. Каждый тайно несёт несколько « серьёзных ошибок чертежа » где-то в одном томе, но если чертёж другого тома исправен, можно жить здоровым, не болея. Однако люди, близкие по крови, наследуют чертежи от совершенно одних предков, поэтому « места их ошибок » очень схожи. Когда у этих двоих рождается ребёнок, « чертёж с багом ровно в том же месте » от отца и от матери складывается вдвойне, ошибку уже нечем прикрыть, и рождается малыш с тяжёлой болезнью или инвалидностью. Из опыта и мудрости человечество создало правило, чтобы избегать этого риска." },
  { id:20, topic:"Переливание и группы", emoji:"🩸",
    question:"Почему нельзя по собственному, неумелому суждению вливать свою « кровь » прямо уколом в тело тяжелораненого, чтобы поделиться ею (переливание)?",
    choices:["Если войдёт чужая кровь, цвет твоих волос станет таким же, как у него","У крови есть группы (A, B, O, AB), и если смешать разные типы, эритроциты яростно отвергают друг друга внутри тела, слипаются, закупоривают сосуды и убивают человека","Если поделиться кровью, твой вес уменьшится вдвое","От чужой крови болит живот"],
    answerIndex:1,
    explanation:"Вся кровь выглядит одинаковой красной жидкостью, но на поверхности эритроцитов есть « антигены » — особые метки (ключи и печати), что показывают тип этой крови. Это группа крови (система ABO). Например, если по ошибке влить кровь типа B в тело человека типа A, команда иммунитета типа A впадает в панику — « вторгся враг, какого я не видел! » — и разом нападает на все входящие эритроциты типа B, спутывая их в плотный комок, как сеть (реакция склеивания). Сгусток закупоривает толстые сосуды лёгких и мозга и мгновенно вызывает смерть от шока. В медицине анализ, проверяющий группу крови, — проверка жизни, которую нельзя пропускать." },
  { id:21, topic:"Хорошо жевать", emoji:"🍽️",
    question:"Когда кладёшь пищу в рот, почему хорошо жевать зубами (более 30 раз) перед глотанием так сильно помогает работе желудка и кишечника?",
    choices:["Если хорошо жевать, пища полностью исчезает во рту","Измельчение пищи на маленькие кусочки во много раз увеличивает общую « площадь поверхности », поэтому пищеварительные соки кишечника быстро пропитывают её целиком и эффективно впитывают питательные вещества","Жевание поднимает температуру в желудке до 100 градусов","Тренировка зубов делает мышцы подошв ног сильнее"],
    answerIndex:1,
    explanation:"Это прекрасное применение математической идеи « площади поверхности ». Если бросить в желудок большой кусок картофеля как есть, желудочный сок (кислота пищеварения) может растворять его лишь с поверхности, поэтому до середины уходят часы, желудок устаёт и расстраивается. Но если зубами разжевать его в мелкую крошку, один большой кусок делится на тысячи крошечных. От деления « суммарная площадь », где пища может касаться пищеварительных соков, расширяется взрывообразно. Благодаря этому, едва она доходит до желудка и кишечника, соки мгновенно пропитывают её до середины, растворяют в кашицу и впитывают 100% питательных веществ для жизни, не оставляя ничего. Хорошо жевать — это самая первая кухонная фабрика, до кишечника." },
  { id:22, topic:"Подавился (спасение)", emoji:"🍖",
    question:"Когда большой кусок пищи застрял в горле и человек задыхается, ты обнимаешь его сзади и сильно толкаешь вверх по животу (приём Геймлиха). В чём настоящая цель давления на живот?",
    choices:["Вдавить живот, чтобы человек выглядел стройнее","Сильное давление на живот толкает вверх воздух, ещё оставшийся в лёгких, и этим давлением воздуха (силой воздушного ружья) с силой выбивает предмет, застрявший в горле","Чтобы напугать червей в животе","Чтобы силой протолкнуть застрявшую пищу вниз, в желудок"],
    answerIndex:1,
    explanation:"Когда что-то застряло в горле и человек не может дышать, на деле в « лёгких » ещё полно невыдохнутого воздуха. Между грудью и животом человека есть большой мышечный « пол » — « диафрагма », что надувает и сжимает лёгкие. Когда обнимаешь сзади и сильно толкаешь вверх чуть выше пупка, органы живота поднимаются вверх, и в свою очередь диафрагма « бах! » сильно сжимает лёгкие снизу. Тогда воздух, оставшийся в лёгких, мгновенно, как яростная буря, устремляется обратно к горлу и, точно воздушное ружьё, выбивает наружу кусок пищи, что закупорил горло. Это прекрасный, основанный на физике приём спасения, использующий устройство человеческого тела." },
  { id:23, topic:"Паразиты и сырое", emoji:"🐛",
    question:"Почему нельзя есть сырое мясо диких животных или пить сырую речную воду без нагрева — страшная причина о червях, что плодятся внутри тела?",
    choices:["От сырого тело человека превращается в животное","Внутри тел существ и в сырой воде таятся паразиты, спрятанные как невидимые яйца, что входят в кишечник человека, кусают стенку и крадут питание или пожирают органы","Сырая вода превращает все кости живота в кашу","От сырого мяса в животе раздаются крики животных"],
    answerIndex:1,
    explanation:"Речная вода в природе и мясо диких оленей, кабанов или свиней почти на 100% таят яйца и личинки крошечных невидимых « паразитов » (как ленточные черви и аскариды). Если съесть их сырыми, они выживают даже в кислоте желудка и доходят до кишечника. Там яйца вылупляются, и длинные вырастают в огромных червей в несколько метров, что присасываются к стенке кишечника и высасывают все питательные вещества, что ты съел ради жизни, оставляя тебя истощённым. Некоторые забираются в мозг или печень и растворяют органы в кашу — злобные черви, угрожающие жизни. Паразиты очень слабы перед огнём (жаром), поэтому нужна мудрость гигиены: прожаривай мясо до середины и кипяти воду, чтобы уничтожить их всех." },
  { id:24, topic:"Допить лекарство", emoji:"💊",
    question:"Когда принимаешь « антибиотики », что врач дал, чтобы убить микробов в теле, какое страшное правило медицины нужно непременно соблюдать?",
    choices:["Как только спала температура и стало легче, сразу бросить по своему суждению, ведь лекарство ценно","Даже если признаки утихли и кажется, что выздоровел, прими всё до самого конца, столько дней, сколько велено, пока микробы в теле не дойдут до нуля","Менять время приёма на разное случайное время каждый день, по прихоти","Если друг простыл, поделись с ним своим остатком лекарства"],
    answerIndex:1,
    explanation:"Когда начинаешь принимать антибиотики, сперва по порядку гибнут « слабые и многочисленные мелкие » микробы. Когда умирает примерно половина, тело чувствует себя как полностью выздоровевшее. Если тут бросить, думая « я уже здоров », те немногие « самые злобные и упрямые микробы, что вынесли удар лекарства » и ещё едва выжили, оживают и снова массово размножаются в теле. Так как эти микробы уже пережили удар и выжили, они превратились в монстров (устойчивые бактерии) с супер-сильным барьером, который лекарство уже не пробить. Тогда даже тот же препарат вовсе не действует, лечения не остаётся, и это ведёт к смерти. Принимать лекарство, не ослабляя хватки, пока не уничтожишь их полностью, — железное правило медицины, что защищает мир." },
  { id:25, topic:"Как бывает обморожение", emoji:"🥶",
    question:"Когда долго пробыл в месте крайнего холода, как заснеженная гора или лёд, почему кончики пальцев рук и ног синеют и теряют чувствительность (« обморожение »)?",
    choices:["Холодный ветер красит поверхность кожи в синий","Чтобы защитить температуру важнейших сердца и органов (центра тела), мозг сужает сосуды на кончиках пальцев и собирает кровь только в центре","В холодном месте вся кровь тела разом замерзает и перестаёт двигаться","Кончики пальцев рук и ног уснули от холода"],
    answerIndex:1,
    explanation:"Это доказательство жестокой, но высшей системы защиты ради выживания, что есть у мозга человека. Когда всё тело подвергается леденящему крайнему холоду, если бы кровь, как обычно, текла до кончиков пальцев, охлаждённая там кровь вернулась бы к сердцу, снизив температуру сердца и мозга (внутреннюю температуру) и вызвав мгновенную смерть от холода. Чтобы это предотвратить, мозг приказывает: « Пожертвуй кончиками пальцев, если надо, но никогда не дай погаснуть огню жизни центрального сердца! » Тогда сосуды рук и ног плотно смыкаются, и кровь перестаёт к ним поступать. У кончиков пальцев, не получающих крови (кислорода), клетки гибнут и синеют, а в худшем случае гниют и отпадают (обморожение). В холодных местах нужно всё время двигать руками и ногами, сразу менять мокрые перчатки и не давать мозгу отдать приказ бросить руки и ноги." },
  { id:26, topic:"Темнота и глаза", emoji:"🌙",
    question:"В миг, когда ночью входишь в тёмную комнату без электричества, ничего не видно, но если постоять неподвижно около 10 минут, очертания мебели и стен вокруг смутно проступают. Почему?",
    choices:["Из глаза человека сам собой начинает бить невидимый луч света","Чёрная дырка в центре глаза (зрачок) широко раскрывается в темноте и меняет форму, чтобы собрать как можно больше слабого света вокруг (как свет звёзд) (адаптация к темноте)","Мозг сам выдумывает тёмный пейзаж и проецирует видение","Со временем цвет ночной тьмы светлеет"],
    answerIndex:1,
    explanation:"Чёрная дырка в центре глаза человека называется « зрачок » и, как диафрагма объектива (отверстие затвора), имеет мышечную « занавеску », что сама регулирует количество входящего света. В светлом месте, как под солнцем, зрачок сжимается размером с кончик иглы, чтобы избыток света не обжёг глаз. Когда оттуда вдруг переходишь в кромешную тьму, сперва света мало и кажется совсем чёрным. Но за примерно 10 минут эта занавеска зрачка раскрывается до предела и начинает изо всех сил подбирать слабые крупинки света по углам комнаты, слишком тонкие, чтобы видеть. Эту систему называют « адаптация к темноте ». Даже в беде в темноте не паникуй: закрыв глаза и подождав неподвижно 10 минут, ты вернёшь компас своего зрения. Это мудрость человеческого тела." },
  { id:27, topic:"Наука слоёв одежды", emoji:"🧥",
    question:"Чтобы утеплиться в очень холодный сезон, почему гораздо теплее носить много тонких слоёв (слоями), чем одну толстую большую вещь?",
    choices:["Больше вещей делают одежду тяжелее, и она вытягивает тепло из земли","Между слоями образуется много слоёв неподвижного воздуха (утеплителя) — самого медленного на Земле проводника тепла, — что полностью преграждают тепло тела от ухода наружу","Когда много тонкой одежды трётся, внутри начинается пожар","От большого количества одежды ветер обходит её стороной"],
    answerIndex:1,
    explanation:"Это тоже прекрасная научная мудрость, использующая свойства вещества. Самый сильный в мире материал по тому, чтобы плохо проводить тепло (преграждать тепло), — на деле неподвижный воздух (газ). Даже если носишь одну толстую вещь, тёплое тепло тела внутри проходит по волокнам ткани и уходит наружу. Но если надеть слоями 3–4 тонкие вещи, в зазорах между одеждой образуется много « комнат воздуха, совсем запертого и неспособного двигаться ». Этот слой воздуха работает как « утеплитель », точно стенка термоса, и становится сильнейшим барьером, что не даёт уйти твоему теплу в 36 градусов и не пускает внутрь леденящий холод. Когда нет одежды, даже набить в неё сухую газету или сухие листья создаёт тот же слой воздуха и может уберечь жизнь от смерти на морозе." },
  { id:28, topic:"Бей или беги", emoji:"🏃",
    question:"Когда перед тобой вдруг появляется свирепый хищник или ты попадаешь в огромную беду, почему сердце вдруг сильно колотится и выступает холодный пот, против твоей воли?",
    choices:["Это знак, что сердце паникует от страха, ломается и вот-вот откажет","Чтобы выжить, мозг начинает готовиться « биться прямо сейчас или нестись прочь во всю мощь » и взрывообразно шлёт огромное количество кислорода (крови) к мышцам всего тела (реакция « бей или беги »)","В беде количество крови в теле удваивается","Чтобы сделать сердце громким и напугать врага напротив до обморока"],
    answerIndex:1,
    explanation:"Когда человек чувствует отчаянный страх или беду, аварийный командный центр в глубине мозга (миндалина) мгновенно чует опасность и разом выбрасывает в кровь особый гормон — адреналин. В миг, когда этот гормон доходит, насос сердца переключается на сверхбыструю работу на полной мощности, поднимает пульс с колотьём и спешно шлёт огромное количество кислорода (крови) к « мышцам ног и рук » для боя или бегства. Одновременно он сужает сосуды кожи, чтобы свести кровотечение к минимуму при ранении, поэтому лицо бледнеет и выступает холодный пот. На языке медицины это называют « реакцией бей или беги ». То, что сердце колотится, — лучший знак защиты: твоё тело, чтобы защитить тебя, высвободило всю энергию и перешло в боевой режим." },
  { id:29, topic:"Роль витаминов", emoji:"🍊",
    question:"Даже если каждый день набивать живот рисом и картошкой, почему заболеваешь (например, цингой), и кровь бьёт из сосудов по всему телу, если месяцами совсем не есть свежих овощей и фруктов?",
    choices:["Если не есть овощи, весь красный цвет крови исчезает","Трёх главных питательных веществ (как углеводы) мало; витамины, что работают как клей, крепко скрепляющий клетки, и как смазка, помогающая химическим реакциям, иссякают","У тела того, кто не ест фрукты, есть правило, что черви пожирают его изнутри","Желудок перестаёт работать, если не видит зелёный цвет овощей"],
    answerIndex:1,
    explanation:"Человек может растолстеть, питаясь рисом и хлебом (углеводами), но одним этим никак не остаться здоровым. Чтобы держать триллионы клеток и стенки сосудов тела в упругом, здоровом состоянии, непременно нужны « витамины » (особенно витамин C и другие) — микронутриенты, что тело не может создать само. Витамины — незаменимые детали для создания « коллагена (клея клеток) », что строит тело. Если их месяцами не хватает, клей клеток по всему телу рвётся в клочья, крошечные сосуды дёсен, кожи и органов повсюду рвутся, и кровь медленно сочится изнутри — страшная болезнь « цинга », и в конце ты умираешь. Не просто набивать живот, а брать малые количества витаминов и минералов — вот правда питания, что поддерживает систему жизни." },
  { id:30, topic:"Жар — это защита", emoji:"🤒",
    question:"Когда микробы простуды или инфекции входят в тело, оно дрожит и появляется высокий жар выше 38 градусов. Почему нельзя сразу силой сбивать жар лекарством — медицинская причина?",
    choices:["Если резко сбить жар, вся вода в теле превратится в кипяток","Жар — это правильная защитная реакция: мозг намеренно поднимает температуру, чтобы команда иммунитета билась лучше всего и чтобы остановить размножение микробов и вирусов, слабых перед жаром","Если сбить жар, выпадут все волосы на голове","При высоком жаре скорость бега возрастает"],
    answerIndex:1,
    explanation:"Поздравляем! На этом первые 30 вопросов « Wise World 3 » завершены. Многие ошибочно думают « жар — это плохо, надо сразу сбивать », но это большая ошибка. Многие микробы и вирусы, что вторгаются в тело, любят нормальную человеческую температуру « около 36 градусов » и размножаются там взрывообразнее всего. Но когда температура поднимается до 38–39 градусов, движение вируса парализуется, и он уже не может размножаться. Наоборот, наша команда иммунитета, как лейкоциты, при высокой температуре тела движется во много раз бодрее и быстрее. Иначе говоря, жар — это стратегия мозга намеренно поднять « температуру комнаты », чтобы взять верх в битве. Охлаждать голову, обильно пить и присматривать за жаром, которым бьётся твоё тело, не сбивая его силой, и отдыхать — вот лучшая мудрость медицины выживания, чтобы это не стало тяжёлой болезнью." },
  { id:31, topic:"Разделение труда", emoji:"🛠️",
    question:"Когда взрослые в обществе не делают все одну и ту же работу, а делятся на разные занятия - земледелец, плотник, врач (« разделение труда ») - в чём наибольшая выгода?",
    choices:["Если бы все делали одну работу, было бы трудно запоминать лица друг друга","Это снимает предел времени, когда один человек должен с нуля освоить все орудия и навыки, и когда каждый специалист сотрудничает, производительность всего общества взлетает","Заниматься разделением труда удваивает рабочие часы каждый день","Чем больше видов занятий, тем оживлённее и веселее на вид"],
    answerIndex:1,
    explanation:"Если бы не было разделения труда, тебе пришлось бы самому растить пшеницу, что ешь, самому строить дом, где живёшь, и, заболев, самому делать лекарство. Так часов в сутках никогда бы не хватило, всё выходило бы наполовину, и жить богато было бы невозможно. Человечество изобрело величайшую мудрость - « разделение труда », где каждый сосредоточен на одной работе и доводит навык до совершенства, а сделанные товары и услуги обмениваются. Это позволяет создавать во много раз более качественные результаты с меньшими усилиями и образует богатое общество, где мы поддерживаем жизнь друг друга с высшей эффективностью." },
  { id:32, topic:"Деньги - это доверие", emoji:"💵",
    question:"Бумажные купюры (валюта), что мы используем каждый день, - всего лишь клочки бумаги, так почему мы можем менять их на вкусную еду и хорошие орудия?",
    choices:["Внутри той бумаги есть волшебный ингредиент, что наполняет живот","Потому что все в обществе вкладывают в эту купюру общее « доверие »: « если я отдам эту бумагу, я всегда смогу обменять её на товар той же ценности »","Потому что закон говорит, что рисунок на купюре - самый красивый в мире","Потому что вес бумаги примерно как у куска железа"],
    answerIndex:1,
    explanation:"Истинная природа денег (валюты) - не их ценность как материала, а « система доверия » между людьми. В древности обменивали само золото и серебро, но они были тяжёлыми и неудобными в переноске, поэтому страны и общества создали общее бумажное орудие - « купюру », чьё доверие они гарантируют. Поскольку обещание и доверие в головах у всех совпадают - « даже если я приму купюру, я смогу так же воспользоваться ею в следующей лавке » - простой клочок бумаги держит мощную способность меняться на товары. В обществе, где доверие рухнуло, купюры буквально превращаются в ничего не стоящие клочки." },
  { id:33, topic:"Мера ценности", emoji:"📏",
    question:"По сравнению с жизнью обмена-бартера, какая удобная и справедливая система родилась, когда « деньги (валюту) » вставили в середину купли и продажи?",
    choices:["От использования денег вес всех товаров падает вдвое","Ценность всех товаров можно выразить общей линейкой под названием « числа », так что даже товары разных видов всегда можно справедливо сравнить по цене и обменять (мера ценности)","Использование денег значит, что торговец всегда даёт тебе подарок","Время сделки всегда становится ровно 1 секунда"],
    answerIndex:1,
    explanation:"У денег есть важная роль « меры ценности », измеряющей ценность всех товаров в числах. В мире бартера без денег тебе пришлось бы каждый раз обсуждать с другим - « во сколько рыб эта овца, во сколько мешков пшеницы, во сколько топоров? » - и расчёт превратился бы в хаос. Но как только деньги, общая линейка, появились в середине, всё можно стало сравнивать одними числами, как « овца - 10 000 монет, рыба - 500 монет ». Это позволило всем торговать справедливо и гладко, без путаницы и без убытка." },
  { id:34, topic:"Хранилище ценности", emoji:"💰",
    question:"Когда ты получаешь много еды, как рыба и овощи, почему лучше один раз превратить её в « деньги (валюту) » и сберечь, чем держать как есть?",
    choices:["Сбережение денег заставляет энергию бить из тела само собой","Еда гниёт за несколько дней, и её ценность падает до нуля, но превратив её в деньги, ты можешь « хранить плод своего труда годами, не давая ему сгнить » (хранилище ценности)","Превращение в деньги удваивает количество еды","Если положить деньги в карман, они сами сияют"],
    answerIndex:1,
    explanation:"Третья великая функция денег - « хранилище ценности ». Даже если ты усердно трудишься и собираешь огромное количество рыбы или бананов, оставив их как есть, они сгниют за несколько дней, и кристалл твоих усилий исчезнет. Так нельзя накопить богатство для будущей беды (голода или травмы). Но быстро превратив собранное в деньги, « орудие, что не гниёт », ты можешь сохранить ценность, ради которой трудился, в точности, как капсулу времени, даже на десять лет вперёд. Деньги - надёжное хранилище для защиты будущего себя." },
  { id:35, topic:"Перенос ценности", emoji:"👛",
    question:"В торговле, вместо переноски тяжёлой картошки или скота как есть, в чём чудесная выгода, с точки зрения перемещения, торговли с помощью « денег (валюты) »?",
    choices:["Держа деньги, твои ноги бегут вдвое быстрее","Ты можешь положить их в маленький кошелёк или карман и « легко перенести ценность своего имущества в любое далёкое место » (перенос ценности)","Деньги плавают на воде, поэтому можно переплыть море","Уход далеко заставляет ценность денег расти сама собой"],
    answerIndex:1,
    explanation:"У денег есть функция « переноса ценности ». Если ты хочешь пойти в дальний город и купить редкое лекарство или прочное орудие, без денег тебе пришлось бы днями тащить пешком тяжёлый урожай или быка. Риск нападения воров по дороге или гибели быка очень высок. Но если ты раз превратишь это богатство в лёгкую, маленькую форму - купюры или монеты - ты можешь спрятать её в кошелёк и в безопасности перенести огромную ценность в дальнюю землю в мгновение и торговать. Это мощная инфраструктура, чтобы экономика перешагнула границы." },
  { id:36, topic:"Договор", emoji:"📝",
    question:"Когда ты даёшь рабочее обещание кому-то или покупаешь и продаёшь товары, почему ты всегда должен оставлять письменный « договор » на бумаге, а не только устное обещание?",
    choices:["Писать много договоров тренирует мышцы руки и делает тебя сильным","Человеческая память становится смутной и меняется со временем, поэтому закрепить содержание обещания письменно предотвращает позднейшие ссоры « ты сказал, не сказал » и обман, и защищает тебя","Обещание, записанное словами, Бог автоматически исполняет волшебством","Держать бумажный документ делает тебя на вид важным"],
    answerIndex:1,
    explanation:"Один из важнейших документов для выживания в обществе - « договор ». Каким бы близким ни был друг, каким бы надёжным ни казался взрослый, ты не должен улаживать только устно обещание вроде « заплачу столько денег через несколько месяцев » или « закончу эту работу к тому времени ». Со временем непременно появится тот, кто переписывает память себе на пользу или лжёт, чтобы увильнуть. Оставив письменное доказательство с подписями и печатями обоих, даже если другой нарушит обещание, ты можешь занять силу окружающих взрослых или закона и защитить себя законно. Договор - это бронежилет для безопасной ходьбы по миру взрослых." },
  { id:37, topic:"Спрос и предложение", emoji:"⚖️",
    question:"На рынке урожай некоего боба резко упал из-за сильного дождя, и количество бобов в мире стало очень малым. Но число людей, которые их хотят, велико. В этот момент как меняется цена бобов?",
    choices:["Поскольку их мало и никто не может купить, цена становится нулём","Это становится дракой среди тех, кто их хочет, и всё больше людей готовы платить даже более высокие деньги, чтобы купить, поэтому цена бобов « резко растёт »","Что бы ни случилось, цена всех товаров всегда постоянна по всему миру","Бобы вырастают в размере, и цена немного падает"],
    answerIndex:1,
    explanation:"Это абсолютный закон, самый базовый в экономике: « спрос (желаемое количество) и предложение (продаваемое количество) ». Цена товаров решается не чьим-то капризом, а автоматически равновесием (весами) этих двух. Когда число желающих купить (спрос) становится подавляюще больше числа товаров на продажу (предложение), ценность товара (ценность редкости) взлетает. Зная эту систему, ты можешь спокойно предвидеть - « чего сейчас не хватает и что востребовано » - и составить план дела, что умно решает беды общества." },
  { id:38, topic:"Что значит прибыль", emoji:"📈",
    question:"В чём истинный, сущностный смысл в обществе получения « прибыли (заработка) » ведением дела?",
    choices:["Обманывая других, бездельничать и жить в роскоши только для себя","В результате решения того, что мучает других (неудобство или забота), своей мудростью и трудом - законно получить ценность выше затраченных издержек (закупочной цены), как « награду за твою благодарность и пользу »","Получать деньги от страны самовольно и класть в карман","Сделать имя своей лавки самым известным в мире"],
    answerIndex:1,
    explanation:"Получать прибыль в деле - вовсе не дурно и не выжимать деньги из кого-то. Прибыль считается как « (цена продажи) минус (закупочная цена или издержки создания) ». Например, для того, кто не может пойти к чистому дальнему источнику, ты несёшь ведро и черпаешь воду, и делишь за 20 монет воду, купленную за 10. Прибыль в 10 монет этой разницы - законная награда благодарности за то, что ты решил его « неудобство передвижения ». Чем больше ты решаешь чью-то боль в обществе, тем больше доверие, называемое прибылью, собирается в твоих руках." },
  { id:39, topic:"Что делает банк", emoji:"🏦",
    question:"Какова была самая основополагающая цель, ради которой место, родившееся в древности под названием « банк », ценилось людьми общества и развивалось?",
    choices:["Украшать комнату множеством красивых купюр и любоваться","Поскольку держать много денег дома рискует кражей ворами, чтобы их « надёжно хранили (вклад) » в прочном сейфе, и чтобы делать безопасные переводы (платежи) в дальние города","Внесение денег само увеличивает размер купюры","Объявить всем, у кого больше всего денег, и похвастаться"],
    answerIndex:1,
    explanation:"Первая цель, ради которой родились банки, - « нужда в надёжном хранении ». Держать золотые монеты или много купюр в своём доме несёт большой риск, что они сгорят в пожаре, или что на тебя нападут грабители и отнимут даже жизнь. Поэтому создали систему « вкладывать » деньги в место с самым прочным сейфом и охраной в обществе. Если вложить деньги в банк, они становятся записью чисел в сберкнижке, и ты можешь на 100% защитить ценное имущество от кражи. Это база мудрости, что безопасно управляет деньгами не как « физическим куском бумаги », а как « доверенными числами »." },
  { id:40, topic:"Долг и проценты", emoji:"💸",
    question:"Когда ты « берёшь деньги в долг » у другого человека или банка, какой страшный экономический механизм ты никогда не должен забывать?",
    choices:["Взятие денег в долг немного укорачивает твой рост","Мало того что ты должен вернуть взятые деньги (основу) как есть - в обмен за время, что ты их брал, ты всегда должен добавить лишние деньги сверху (проценты) и вернуть больше","Правило, что раз взяв деньги в долг, ты больше никогда не можешь делать покупки","Что взятые деньги можно держать как свои, не возвращая"],
    answerIndex:1,
    explanation:"Брать деньги в долг - это « брать вперёд » труд и свободу твоего будущего себя. Долг всегда несёт арендную плату под названием « проценты » или « ставка ». Например, если взять 10 000 монет, а правило процентов - 10%, то потом надо вернуть 11 000 монет. Если относиться к этому механизму процентов легкомысленно, сколько ни плати, расчёт процентов всё разбухает (как снежный ком), и ты кончаешь рабской жизнью, платя деньги за других всю жизнь. Если нет верного плана нарастить деньги, лёгкого долга надо абсолютно избегать." },
  { id:41, topic:"Инвестиция и трата", emoji:"🌱",
    question:"Есть два способа использовать деньги. В отличие от « траты » - купить сладости, что ешь сейчас и что сразу исчезают, - что есть конкретный пример « инвестиции », использования денег ради роста твоей будущей силы и богатства?",
    choices:["Купить много яркой одежды последней моды","Купить прочное « орудие » для начала нового своего дела, или потратить деньги на « книги (учёбу) », чтобы обрести знания","Влить все имеющиеся деньги в азартные игры в казино или в играх","Положить деньги на тарелку и просто пристально смотреть"],
    answerIndex:1,
    explanation:"Если ты только тратишь деньги (трата/мотовство), деньги просто исчезают из твоих рук, и всё. Но мудрый человек использует деньги как « семя (инвестицию) ради умножения своей будущей силы ». Например, если тот, кто строгал дерево руками, скопит деньги и купит топор хорошего качества (орудие), со следующего дня он может делать в 10 раз больше дров за то же время, и приходящие деньги резко растут. Также покупать и изучать книги по медицине или науке - сильнейшая « инвестиция в себя », превращающая собственный мозг в лучшее орудие заработка. Двигайся, рассчитывая, на что потратить деньги, чтобы будущее стало богатым." },
  { id:42, topic:"Налоги и общественные блага", emoji:"🌉",
    question:"Почему абсолютно нужна система, где все в деревне или городе понемногу вносят часть заработанных денег - « налоги » или собранные деньги (общественные средства)?",
    choices:["Чтобы использовать собранные деньги и устраивать каждый день большой праздник всем вместе","Чтобы всем вместе содержать « общий колодец, прочные дороги, большие мосты и больницы, что помогают больным (общественные блага) », что деньги одного человека никогда не создадут, и защищать общество","Чтобы собрать много денег и закопать глубоко в землю","Чтобы сделать дом некоего великого вождя роскошным, как замок"],
    answerIndex:1,
    explanation:"Если бы у общества вовсе не было налогов или денег, вносимых вместе (общественных средств), никто в одиночку не смог бы заплатить огромные деньги, чтобы возвести большой мост или замостить длинные дороги. Если дороги в руинах, никто не может передвигаться из страха травмы, и дело и жизнь полностью рушатся. Именно поэтому все понемногу вносят деньги и складывают, чтобы строить и содержать « общую инфраструктуру, что никто не сделает в одиночку (общественные блага) ». Эта система взаимной поддержки (социальная защита и общественная помощь) - сама основа благосостояния, что защищает безопасность мира." },
  { id:43, topic:"Ценность труда", emoji:"💪",
    question:"В чём сущностная, наибольшая ценность как человека от « работы (труда) » в обществе?",
    choices:["Получать приказы от кого-то и просто двигать телом, как робот","Использовать свою чудесную энергию « времени, навыка и мудрости », чтобы решить чьё-то « неудобство или беду (боль) » в обществе и сделать мир лучше, чем вчера","Работать больше часов, чем другие, ломать тело и хвастаться","Получить лицензию делать что угодно, лишь бы получать деньги"],
    answerIndex:1,
    explanation:"Истинный облик работы - не просто задача ради получения денег. Это действие создания ценности: предложить обществу своё драгоценное время жизни и навыки и превратить чьё-то « я в беде! » в « как хорошо! ». Земледелец, делая вкусную еду, стирает голод, а врач, давая лечение, стирает боль. Через работу ты нужен внутри общества и становишься важной частью головоломки, что поддерживает чью-то жизнь. Правильно знать цель работы укрепляет гордость твоей жизни и ноги твоей независимости." },
  { id:44, topic:"Опасность монополии", emoji:"👑",
    question:"Когда на рынке есть « только одна лавка », продающая некое важное лекарство (монополия), почему это очень опасно для покупателя?",
    choices:["С одной лавкой запоминать название лавки становится в тягость","Поскольку нет соперника для соревнования, даже если хозяин несправедливо вздёрнет цену до « невероятно высокой », у покупателя нет выбора, кроме как платить эти высокие деньги, чтобы жить","С одной лавкой форма лекарства сама превращается в треугольник","Опасности нет; одна лавка всегда безопаснее"],
    answerIndex:1,
    explanation:"Состояние без единого соперника на рынке называется « монополия ». Когда возникает монополия, красивые весы спроса и предложения ломаются, и продавец может свободно управлять ценой, как бог. Даже если лекарство, что должно продаваться за 10 монет, тебе объявляют « это 10 000 монет; не нравится - не покупай и болей », происходит эксплуатация, где всё твоё состояние забирают, чтобы ты жил. Именно поэтому здоровое общество защищает систему « конкуренции », где несколько лавок продают похожие товары и соперничают, и ставит барьер, чтобы цены не росли несправедливо." },
  { id:45, topic:"Слишком хорошая ловушка", emoji:"🎣",
    question:"Незнакомый взрослый сделал тебе сладкое приглашение: « Если поможешь мне с этой работой, я дам тебе в мгновение огромную сумму денег, какой ты никогда не видел ». Что надо сделать?",
    choices:["Раз это шанс получить большую сумму, помочь сразу, не думая","Категорически отказаться и уйти с места. В этом мире « работы без риска, где легко получаешь большую сумму », 100% никогда не существует; это ловушка, чтобы заставить тебя нести часть преступления и разрушить твою жизнь","Позвать много друзей и делать эту работу всем вместе","Сделать на месте бумажный договор о том, сколько получишь"],
    answerIndex:1,
    explanation:"Холодное, абсолютное правило экономики: « размер награды (полученных денег) полностью пропорционален размеру предоставленной ценности и размеру несомого риска ». За историей дать ребёнку без всякого особого навыка большую сумму в мгновение 100% спрятана зверская преступная ловушка - « перевозка наркотиков » или быть « получателем мошенничества, что обманывает людей и забирает деньги », - что одним махом приводит к аресту полицией и полностью кончает жизнь. Мудрость остерегаться оком логики тех, кто подходит со сладкими словами, и наотрез отказывать защищает твою свободу на всю жизнь." },
  { id:46, topic:"Инфляция", emoji:"🎈",
    question:"Когда « общее количество денег », что циркулирует в мире, печатается между странами и банками в чрезмерных количествах и растёт слишком сильно, что происходит с ценами всего общества (ценами вещей)?",
    choices:["Поскольку денег стало много, цена всех вещей падает до 1 монеты","Поскольку ценность редкости денег (их редкость) падает и приближается к клочку бумаги, относительно « цена всех вещей резко растёт (инфляция) »","Даже если количество денег меняется, цена вещей на Земле никогда не меняется","Вещи начинают превращаться в форму купюр"],
    answerIndex:1,
    explanation:"Это механизм « инфляции », динамичной болезни экономики. Что было бы, если бы страна печатала купюры бесконечно и раздавала всем? Поскольку у всех много денег, теперь возникает драка за « вещи ». Тогда происходит страшное явление, где хлеб, что вчера можно было купить за 100 монет, на следующий день нельзя купить без 10 000 монет, а через день - без 1 000 000 монет. Ценность денег рушится, и сила денег, что ты бережно копил, в мгновение становится мусором. Знать равновесие « количества » денег и « числа » вещей даёт тебе широкий взгляд на мир." },
  { id:47, topic:"Ловушка отложенной оплаты", emoji:"💳",
    question:"В чём скрытая величайшая ловушка системы (кредита), где « у меня нет денег сейчас, но если я покажу эту карту (или дам обещание), я могу купить прямо сейчас и заплатить в следующем месяце »?",
    choices:["В следующем месяце купленное орудие исчезает само","Поскольку деньги не убывают из твоего кошелька прямо сейчас, твоё чувство, насколько ты беднеешь сейчас, немеет, и ты кончаешь тем, что несёшь долг, что твой будущий ты абсолютно никогда не сможет оплатить","Если потеряешь карту, твоё имя полностью меняется","В момент покупки вес всего твоего тела удваивается"],
    answerIndex:1,
    explanation:"Кредитные карты и « в долг » (кредит) - очень удобные орудия, но и опасная ловушка, бьющая по слабому месту человеческого мозга. Когда « купюры » физически убывают из кошелька, человек чувствует сильную боль (страх потери) и может затормозить, но при обещании чисел (плати позже) мозг вовсе не чувствует боли. Поэтому ты беззаботно тратишь « деньги, что твой будущий ты должен заработать тяжёлым трудом ». В следующем месяце, когда не можешь заплатить, добавляются проценты, и ты банкротишься в мгновение. Жить в пределах наличных в руках - основа экономической независимости." },
  { id:48, topic:"Издержки упущенной выгоды", emoji:"⏳",
    question:"У тебя есть « 1 час » времени или « 1 000 монет » денег. Когда ты выбираешь, что с этим делать, что значит экономическое понятие, что ты никогда не должен забывать, « издержки упущенной выгоды »?",
    choices:["Особый сбор, что ты должен платить стране каждый раз при покупке","Выбрать один вариант значит одновременно, что « ты отказываешься и выбрасываешь другую чудесную возможность или ценность, что мог бы получить, если бы не выбрал его » (компромисс)","Система, где долгое использование орудия само повышает его ценность","Это значит, что время, что ты проводишь, спя дома без дела, не стоит ни одной монеты"],
    answerIndex:1,
    explanation:"Наши ресурсы, как время и деньги, « полностью конечны (имеют предел) » для всех в мире. Если ты купишь игру за 1 000 монет, возможность купить учебную книгу за эти 1 000 монет исчезает навсегда. Если потратишь 1 час на игру, возможность использовать этот час на работу или учёбу исчезает. Эту « другую наибольшую ценность, что ты тайно жертвуешь за кулисами, выбирая что-то », называют « издержками упущенной выгоды ». Мудрый человек, что это знает, решая что-то, взвешивает « делая это, что я теряю взамен? » и может сделать наименее плохой выбор." },
  { id:49, topic:"Складываться вместе", emoji:"🤝",
    question:"Когда земледельцы деревни очень хотят использовать « огромную сельхозмашину (трактор) », слишком дорогую, чтобы один человек её купил, какова мудрейшая экономическая мудрость, чтобы получить её, объединив силы?",
    choices:["Молиться каждый день и ждать, пока кто-то разбогатеет и купит её тебе в подарок","Все понемногу вносят деньги и складывают (кооператив), покупают одну машину как общее орудие всех и используют по очереди по справедливому графику","Прокрасться ночью в поле другого города и тихо украсть машину","Отказаться от покупки машины и всем делать руками всю жизнь"],
    answerIndex:1,
    explanation:"Даже если капитал одного человека (деньги, что у него есть) мал, когда много людей собираются с одной целью и вносят деньги, чтобы сделать один мощный ком, эту экономическую систему, что решает огромную задачу, называют мудростью « кооперации » или « микрофинансов ». Если использовать машину, купленную на сложенные деньги, урожай поля у всех растёт во много раз, и к всем возвращается больше денег, чем внесли. Вместо зависимости от сильного богача слабые на равных решают правила, вместе вносят средства и самостоятельно, самодостаточно создают богатство - прекраснейшая система экономической сферы." },
  { id:50, topic:"Равная сделка", emoji:"🛒",
    question:"Когда ты делаешь покупку и платишь деньги, каково правильное отношение как людей между « стороной, что платит (покупателем) » и « стороной, что продаёт (продавцом) », что принимает купюру и отдаёт товар?",
    choices:["Платящий покупатель велик, как бог, поэтому можно издеваться над продавцом","Продавец предлагает « товар чудесной ценности », а покупатель предлагает « доверенные деньги той же ценности » - они « полностью равные партнёры наравне », основанные на взаимном согласии","Лавка, что продаёт товар, более велика, поэтому покупатель всегда должен лебезить и подчиняться","Кто более велик, решается погодой того дня"],
    answerIndex:1,
    explanation:"Очень частая, уродливая ошибка в обществе - заблуждение, что « платящая сторона может задирать нос ». Дело - не верх-низ силы, а « равный, равноценный обмен » ценности друг друга. Без удобного орудия, что продавец сделал тяжёлым трудом, твоя монета в 100 остаётся простым куском металла. Наоборот, без твоих денег продавец не может купить другие вещи. Каждый оказывает другому уважение - « спасибо, что продал », « спасибо, что купил » - это смазка общества и лучшая основа, чтобы держать вращающейся добрую экономическую сферу." },
  { id:51, topic:"Видеть сквозь рекламу", emoji:"📺",
    question:"Ты увидел « рекламу (ролик) » по ТВ, в интернете, на щитах и т.п., подающую товар как невероятно привлекательный. Чего надо остерегаться, видя это?",
    choices:["То, что говорит реклама, - 100% абсолютная правда, поэтому надо всему поверить и сразу купить","Поскольку цель рекламы - « заставить тебя тратить деньги, чтобы они получили прибыль », усомнись раз в красиво украшенном виде и словах, и спокойно рассчитай, есть ли в нём сущностная ценность, что тебе по-настоящему нужна","Увидев рекламу, скажи всем друзьям « если не купишь это, заболеешь »","Все, кто появляется в рекламе, - плохие люди, поэтому надо всегда злиться"],
    answerIndex:1,
    explanation:"Техники рекламы и маркетинга сделаны, чтобы досконально исследовать человеческие чувства « хочу! » и « у всех есть, я тоже хочу похвастаться! » (слабое место психологии), чтобы заставить тебя открыть кошелёк. Даже если милый персонаж или знаменитость говорит « это лучшее », это лишь реплика, что они говорят, получив рекламные деньги. Человек, что глотает информацию СМИ как есть (без медиаграмотности), всю жизнь танцует ради чужой прибыли, и его кошелёк опустошают. Имей сообразительность видеть сквозь « цель, что за » информацией." },
  { id:52, topic:"Как работает страховка", emoji:"🛡️",
    question:"Как называют общую миру систему взаимопомощи, где против огромного несчастья-кризиса, как « тяжёлая травма, тяжёлая болезнь или большой пожар дома », о котором никто не знает, когда и с кем случится, все понемногу вносят деньги, чтобы подготовиться?",
    choices:["Покупки","Страховка (взаимопомощь)","Монополия","Сбережения"],
    answerIndex:1,
    explanation:"Если ты живёшь совсем один и вдруг получаешь тяжёлую болезнь, нуждающуюся в миллионах монет медицинских расходов, ты не можешь заплатить и теряешь жизнь вот так. Поэтому человечество изобрело « страховку », экономический щит, что мягко спасает друг друга. С пока здоровы, много людей вносят малые деньги - как 100 монет каждый месяц - в один большой сейф и копят. И когда один из членов по несчастью получает тяжёлую травму, из этого сейфа выдают большую сумму, чтобы покрыть стоимость лечения. Это прекраснейшая мудрость человечества рассеивать риск: « один за всех, все за одного »." },
  { id:53, topic:"Перелов и устойчивость", emoji:"🐟",
    question:"Рыбак, говоря « если поймаю много сейчас, заработаю много », каждый день разом вылавливал всю рыбу в море, не оставляя ни одной, вплоть до маленьких мальков (перелов). Почему это дело наверняка провалится через несколько лет и будет голодать?",
    choices:["Слишком много рыбы злит морского бога, и он превращает все купюры в песок","У природных ресурсов (растений и животных) есть « скорость восстановления » рождения детей и увеличения, и если её превысить и довести их до вымирания, то, что ты продашь в будущем, полностью исчезает (крах устойчивости)","Поймав слишком много рыбы, она становится такой тяжёлой, что лодка взлетает в небо","Когда число рыб падает, температура морской воды поднимается до 100 градусов и это опасно"],
    answerIndex:1,
    explanation:"Понятие, что никогда нельзя игнорировать, чтобы экономика длилась вечно, - « устойчивость ». Природные блага Земли - не бесконечно бьющий источник. Великий принцип - использовать рыбу и лесные деревья в пределах скорости, с какой они растут естественно, словно получая немного « процентов ». Глупый делец, что думает лишь о сиюминутной прибыли, своими руками разрушает природу, основу, и через несколько лет морит всех голодом и самоуничтожается. Имей широкий взгляд жить мудро, оставляя ресурсы детям будущего." },
  { id:54, topic:"Редкие навыки", emoji:"🧠",
    question:"Человек, что получает много « жалованья (вознаграждения) » за работу в обществе, - не просто крупный телом или тот, кто задирает нос, а человек с каким качеством?",
    choices:["Человек, что громче всех каждый день кричит, чтобы ему дали денег","Человек, у кого есть « особое знание, высокий навык, глубокий опыт », что никто другой не может легко повторить, и кто может решить большие беды общества (редкий талант)","Человек, что лучше всех в мире отлынивает в рабочие часы","Человек, что не выходит из дома каждый день и просто спит неподвижно"],
    answerIndex:1,
    explanation:"Правило, решающее размер жалованья, тоже на деле движется по закону « спроса и предложения ». У лёгкой работы, что любой может повторить за 1 секунду, есть десятки тысяч людей в мире, что могут сделать вместо тебя, поэтому жалованье низкое. Но человек со « специализированным знанием (навыком) », обретённым через долгие годы учёбы и усилий - как « я могу прооперировать и вылечить эту трудную болезнь » или « я могу разработать удобную систему, что никто не может сделать » - становится « редким, высокоценным талантом » без замены в мире. Если хочешь получать много денег, правильный ответ - не кричать громко, а шлифовать голову и навык и стать единственным в своём роде существом, что общество ищет." },
  { id:55, topic:"Польза конкуренции", emoji:"🏁",
    question:"На одной улице появились две лавки, продающие мясо, « Лавка A » и « Лавка B » (конкуренция). Какую чудесную пользу приносит покупателям (горожанам) соперничество этих двух лавок?",
    choices:["С двумя лавками вкус мяса сам превращается в шоколадный","Чтобы покупатель выбрал их лавку, каждая отчаянно начинает изобретать « сделаем цену дешевле » и « сделаем мясо свежее и вкуснее »","Две лавки каждый день яростно дерутся на кулаках, и можно смотреть","Покупка мяса всегда занимает вдвое больше времени"],
    answerIndex:1,
    explanation:"То, что соперники, продающие один товар на рынке, соревнуются, называется « конкуренция ». С конкуренцией хозяева не могут отлынивать. Если бы Лавка A продавала плохое мясо дорого, все покупатели ушли бы в Лавку B, и Лавка A обанкротилась бы. Именно поэтому каждая отчаянно работает головой и повторяет изобретение « как доставить всем дешевле и лучше ». Эта энергия конкуренции - двигатель, что заставляет технику, медицину и качество услуг всего общества развиваться всё больше каждый день." },
  { id:56, topic:"Рост производительности", emoji:"🚜",
    question:"Как называют, в экономических терминах, величайший прогресс - введение « железных орудий и тракторов (машин) », сделанных с помощью мудрости, от жизни вспашки полей руками?",
    choices:["Расширение траты","Рост производительности","Возрождение бартера","Завершение монополии"],
    answerIndex:1,
    explanation:"Даже при том же времени и той же человеческой рабочей силе увеличить количество результатов, что можно произвести, во много или в десятки раз, используя превосходные орудия, машины и системы, называется « ростом производительности ». Человек, что брал целый день руками, чтобы выкопать одну картофелину, может, используя трактор, собрать 100 картофелин за один час. Когда производительность растёт, еда и богатство переполняют общество в больших количествах, и даже без того, чтобы все работали долгие часы, потея как рабы, можно создать свободное время (досуг), где все могут жить безопасно, не спеша и богато. Мудрость облегчает труд." },
  { id:57, topic:"Торговля и распределение", emoji:"🚢",
    question:"В чём чудесный смысл системы « торговли » или распределения, где ты обмениваешь редкую соль или лекарство, что никогда не добыть в своём регионе, на одежду, что есть у людей в дальнем, ином регионе?",
    choices:["Уход далеко смешивает названия стран друг с другом и заставляет их исчезнуть","Обменивая сделанное с использованием « сильных сторон ресурсов и климата, в которых хороша каждая земля Земли », все могут поровну наслаждаться богатством, что один регион никогда бы не добыл","Заниматься торговлей сжимает размер Земли вдвое","Правило, что покупка дальних товаров всегда выращивает плесень на купюрах"],
    answerIndex:1,
    explanation:"На Земле всегда есть неравенство ресурсов по регионам: холодные места, тёплые места, места с многими горами, места у моря. Если запереться в одной деревне, живя самодостаточно, люди в регионах, где не добыть соль, заболевают и умирают. Человечество развило мудрость « распределения и торговли », связывая и обменивая с дальними регионами фирменные продукты, сделанные с использованием силы каждой земли. Это создало глобальную сеть взаимопомощи, где все люди мира делятся друг с другом благами всей Земли и могут безопасно черпать богатство, где бы они ни были." },
  { id:58, topic:"Асимметрия информации", emoji:"🔍",
    question:"Когда ты идёшь купить орудие, почему ты не должен покупать сразу только по цене, увиденной в первой лавке, а обойти несколько других лавок и рынок, чтобы посмотреть их цены (собрать информацию)?",
    choices:["Много ходить усиливает трение подошв твоей обуви и заставляет бегать быстрее","Если между продавцом и покупателем есть « разрыв информации (состояние, где только одна сторона знает правду) », есть опасность, что тебя заставят купить по несправедливо высокой цене (надувательство) выше рыночной и ты сильно потеряешь","Обход многих лавок превращает цвет купюр в красивое золото","Закон, что покупка в одной лавке огорчает человека лавки"],
    answerIndex:1,
    explanation:"В деле непременно есть плохие люди, что, пользуясь тем, что покупатель не знает истинной ценности или рыночной цены (средней цены) товара, вздувают цену в 10 раз против обычной и пытаются обмануть. В экономических терминах это называется « асимметрия информации ». Чтобы не попасть в эту ловушку, перед тем как открыть кошелёк, собрать самому « данные информации », открыв книги или обойдя несколько лавок, - сильнейший барьер. У того, у кого нет знаний, забирают деньги, а тот, у кого есть верная информация, может защитить себя - такова суровая реальность общества." },
  { id:59, topic:"Пожертвование и дарение", emoji:"🎁",
    question:"Не прося никакой отдачи, действие поделиться своими деньгами или едой с человеком, по-настоящему без денег в беде, или с человеком, что ранен и не может работать (пожертвование или дарение) - в чём его истинная мудрость в обществе?",
    choices:["Просто бросить деньги в канаву и нарочно сделать себя бедным ради забавы","Убирая из общества « людей, что в отчаянии могут лишь свернуть к преступлению » или « людей, что умирают от голода », и поднимая безопасность (порядок) и доброту всего города, ты можешь, в свою очередь, надёжнее всего защитить свою собственную жизнь и будущую безопасность","Дать деньги другим заставляет новые деньги падать с неба на следующий день","Задирать нос перед человеком в беде и чувствовать себя ставшим великим богом"],
    answerIndex:1,
    explanation:"Истинная природа « пожертвования или дарения » без отдачи - не просто самопожертвенное волонтёрство. Это инвестиция в мудрейшую « социальную сеть безопасности (линию обороны) », чтобы предотвратить страшный крах порядка, где у общества выпадает дно и люди в бедности не могут жить без совершения преступления. Добрые деньги, что ты сегодня использовал, чтобы спасти чужую боль, возвращаются к тебе, в свою очередь, как наибольшая ценность безопасного города, где завтра ты сам не подвергаешься нападению воров. Пускать доброту по кругу - величайшая социальная мудрость человечества, чтобы выжить, не самоуничтожаясь." },
  { id:60, topic:"Стать хозяином денег", emoji:"🧭",
    question:"Узнав в Пакете 2 этого приложения « Wise World 3 » о системе доверия за многой экономикой и купюрами, какова истинная конечная цель в твоей собственной жизни?",
    choices:["Накопить больше всех денег в мире и стать королём, что командует другими и правит ими деньгами","Не стать рабом денег, орудия чисел, а верно видеть сквозь « систему доверия и благодарности » за купюрами, использовать свою мудрость, чтобы мягко править деньгами, и владеть ими, чтобы защищать права человека и счастье себя и окружающих","Делать покупки до предела каждый день и наполнить дом мусором, конец","Получить трофей за все верные ответы и совсем бросить учиться"],
    answerIndex:1,
    explanation:"Поздравляем! На этом все 30 вопросов Пакета 2 завершены. Деньги, если использовать их на шаг неверно, превращаются в страшную дьявольскую цепь, что заставляет людей сомневаться, заставляет предавать и крадёт свободу людей на всю жизнь. Но если ты держишь « компас экономической мудрости », что узнал в этой викторине, тебя уже не обманут числа на купюрах. Деньги - лишь удобное орудие, что делает « энергию доверия », рождённую, когда ты решаешь чью-то беду, легко переносимой. Вместо того чтобы быть управляемым деньгами, используй свою мудрость, чтобы стать « хозяином, что мягко их контролирует ». И, на равных и справедливо с друзьями по всему миру, сотрудничай, чтобы построить своими руками добрый мир, где никто не голодает. Весь мир болеет за твою мудрую независимость!" }
];
